module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output reg res_valid,
    output [15:0] result
);
    reg [15:0] dividend_128;      // 16-bit dividend (128 = 8-bit dividend << 8)
    reg [15:0] divisor_16;        // 16-bit divisor (16 = 8-bit divisor << 8)
    reg [16:0] sr;                // Shift register (17-bit)
    reg [3:0] cnt;                // Counter (4-bit)
    reg done;                     // Done flag (1-bit)
    reg [16:0] sub_result;        // Subtractor result (17-bit)
    reg mux_sel;                  // MUX select (1-bit)
    reg [15:0] neg_divisor;       // Negated divisor (16-bit)
    reg start_cnt;                // Start counter flag (1-bit)
    reg rst_cnt;                  // Reset counter flag (1-bit)
    // MUX for selecting the input for the shift register
    always @(*) begin
        if (mux_sel)
            sub_result = sr + neg_divisor;
        else
            sub_result = sr;
    end
    // Shift register
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            sr <= 17'b0;
        end else if (start_cnt) begin
            sr <= dividend_128;
        end else if (start_cnt == 1'b0) begin
            if(done)
                if(sign)
                    if(dividend[7]^divisor[7])
                        sr[15:8] <= ~sr[15:8] + 1'b1;
                    else
                        sr[15:8] <= sr[15:8];
                else
                    sr[15:8] <= sr[15:8];
            else
                sr <= sub_result[15:0];
        end
    end
    // Counter
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            cnt <= 4'b0;
        end else if (start_cnt) begin
            cnt <= 4'b1;
        end else if (start_cnt == 1'b0) begin
            if(!done)
                cnt <= cnt + 1'b1;
            else
                cnt <= cnt;
        end
    end
    // Done flag
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            done <= 1'b0;
        end else if (start_cnt) begin
            done <= 1'b0;
        end else if (start_cnt == 1'b0) begin
            if(cnt[3])
                done <= 1'b1;
            else
                done <= done;
        end
    end
    // Negated divisor
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            neg_divisor <= 16'b0;
        end else if (opn_valid && !res_valid) begin
            neg_divisor <= (~divisor_16) + 1'b1;
        end
    end
    // Res_valid
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            res_valid <= 1'b0;
        end else if (start_cnt) begin
            res_valid <= 1'b0;
        end else if (start_cnt == 1'b0) begin
            if(done)
                res_valid <= 1'b1;
            else
                res_valid <= res_valid;
        end
    end
    // Dividend_128
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            dividend_128 <= 16'b0;
        end else if (opn_valid && !res_valid) begin
            dividend_128 <= {dividend, 8'b0};
        end
    end
    // Divisor_16
    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            divisor_16 <= 16'b0;
        end else if (opn_valid && !res_valid) begin
            divisor_16 <= {divisor, 8'b0};
        end
    end
    // Result
    assign result = sr[15:8] | sub_result[15:8];
endmodule
